# ── 1.6 Cluster exons by BP mutational signature ──────────────────────────────

cluster_exons <- function(df, k = 2) {
  mat <- df %>%
    filter(coord_rel %in% 1:7, mut_type == "sub", order_bp == 1) %>%
    group_by(exon_id, coord_rel) %>%
    summarise(median = median(delta_psi, na.rm = TRUE), .groups = "drop") %>%
    pivot_wider(names_from = coord_rel, values_from = median) %>%
    column_to_rownames("exon_id") %>%
    as.matrix()
  mat[is.na(mat)] <- 0
  hc <- hclust(dist(mat, method = "manhattan"), method = "ward.D2")
  data.frame(exon_id = hc$labels, order = hc$order,
             cluster = cutree(hc, k = k)) %>%
    arrange(cluster, order) %>%
    mutate(exon_id = factor(exon_id, levels = exon_id))
}

psi_df_bp$mut_type <- factor(psi_df_bp$mut_type,
                             levels = c("sub", "∆1nt", "∆3nt", "∆6nt"))

order_row_manual <- psi_df_bp %>%
  filter(label == "manual") %>%
  cluster_exons(k = 1)

order_row_predicted <- psi_df_bp %>%
  filter(label == "predicted", wt_psi >= 5, wt_psi <= 95, order_bp == 1) %>%
  cluster_exons(k = 2)

groups <- bind_rows(
  order_row_manual    %>% transmute(exon_id = as.character(exon_id),
                                    group   = "Yes\nManual"),
  order_row_predicted %>% transmute(exon_id = as.character(exon_id),
                                    group   = ifelse(cluster == 1,
                                                     "Yes\nPredicted",
                                                     "No\nPredicted"))
) %>%
  mutate(group = factor(group,
                        levels = c("Yes\nManual", "Yes\nPredicted", "No\nPredicted")))

# Export cluster labels (used by downstream comparison analyses)
groups %>%
  mutate(cluster_label = case_when(
    group == "Yes\nManual"    ~ "Manual",
    group == "Yes\nPredicted" ~ "Predicted Cluster 1",
    group == "No\nPredicted"  ~ "Predicted Cluster 2"
  )) %>%
  select(exon_id, cluster_label) %>%
  fwrite(file.path(results_dir, "bp_cluster_groups.tsv"), sep = "\t")

