base_theme <- theme_minimal() +
  theme(
    plot.background  = element_rect(color = NA),
    panel.grid       = element_blank(),
    axis.ticks       = element_line(color = "black", linewidth = 0.5),
    axis.line        = element_line(color = "black", linewidth = 0.5),
    axis.text        = element_text(size = 10, color = "black", family = "Helvetica"),
    axis.title       = element_text(size = 10, color = "black", family = "Helvetica"),
    legend.text      = element_text(size = 10, color = "black", family = "Helvetica"),
    legend.title     = element_text(size = 10, color = "black", family = "Helvetica")
  )

plot_heatmap <- function(df,
                         x         = coord_rel,
                         y         = exon_id,
                         fill      = median,
                         label_col = NULL,
                         pseudo_log = FALSE,
                         sigma     = 10,
                         limits    = c(-100, 100),
                         x_labels  = NULL,
                         legend    = FALSE,
                         facet_row = NULL,
                         facet_col = NULL) {
  fill_scale <- if (pseudo_log) {
    scale_fill_gradientn(colours = delta_colours, limits = limits,
                         breaks = c(-100, -50, -25, -5, 0, 5, 25, 50, 100),
                         trans = pseudo_log_trans(sigma = sigma), oob = squish,
                         guide = "colourbar", na.value = "grey60")
  } else {
    scale_fill_gradientn(colours = delta_colours, limits = limits,
                         oob = squish, guide = "colourbar", na.value = "grey80")
  }
  p <- ggplot(df, aes(x = as.factor({{ x }}), y = {{ y }}, fill = {{ fill }})) +
    geom_tile() + fill_scale +
    theme_minimal() +
    theme(panel.grid = element_blank(), axis.ticks = element_blank(),
          axis.title = element_blank(), axis.text = element_blank(),
          legend.text  = element_text(size = 14, color = "black"),
          legend.title = element_text(size = 14, color = "black"),
          plot.background = element_rect(color = NA),
          strip.text.y = element_blank(),
          legend.position = if (legend) "bottom" else "none") +
    labs(fill = "∆PSI")
  if (!is.null(label_col))
    p <- p + geom_text(aes(label = .data[[label_col]]), size = 5)
  if (!is.null(x_labels))
    p <- p + scale_x_discrete(breaks = x_labels$pos, labels = x_labels$consensus)
  if (!is.null(facet_row) || !is.null(facet_col))
    p <- p + facet_grid(rows = facet_row, cols = facet_col,
                        scales = "free", space = "free")
  p
}

plot_violin <- function(df, x = coord_rel, y = delta_psi,
                        x_labels = NULL, faceted = FALSE, facet_var = mut_type) {
  p <- ggplot(df, aes(x = as.factor({{ x }}), y = {{ y }})) +
    geom_violin(color = "black", linewidth = 0.2, width = 1,
                alpha = 0.5, fill = "#A6CEE3") +
    geom_boxplot(color = "black", linewidth = 0.2, width = 0.1,
                 outliers = FALSE, fill = "#A6CEE3") +
    stat_summary(aes(group = 1), fun = median, geom = "line",
                 linewidth = 0.4, color = "black") +
    theme_minimal() +
    theme(axis.line    = element_line(color = "black"),
          axis.ticks   = element_line(color = "black"),
          axis.text    = element_text(size = 10, color = "black", family = "Helvetica"),
          axis.title.x = element_blank(),
          axis.text.y  = element_text(size = 10, color = "black", family = "Helvetica"),
          panel.border = element_blank(), panel.grid = element_blank(),
          legend.position = "none") +
    ylab("∆PSI")
  if (!is.null(x_labels))
    p <- p + scale_x_discrete(breaks = x_labels$pos, labels = x_labels$consensus)
  if (faceted) p <- p + facet_grid(rows = vars({{ facet_var }}))
  p
}

plot_group_violin <- function(data, y_var, y_lab, title_str, step_increase = 5,
                             out_path = NULL) {
  wtest <- data %>%
    wilcox_test(as.formula(paste(y_var, "~ group")),
                paired = FALSE, p.adjust.method = "BH") %>%
    add_significance() %>%
    add_xy_position(x = "group", step.increase = step_increase) %>%
    mutate(y.position = case_when(
      group1 == "Yes\nManual"    & group2 == "Yes\nPredicted" ~ min(y.position),
      group1 == "Yes\nPredicted" & group2 == "No\nPredicted"  ~ min(y.position),
      group1 == "Yes\nManual"    & group2 == "No\nPredicted"  ~ max(y.position),
      TRUE ~ y.position
    ),
    p.adj.signif = ifelse(p > 0.01, 'ns', p.adj.signif))
  cat("\n---", title_str, "---\n")
  wtest_out <- as.data.frame(wtest[, c("group1", "group2", "n1", "n2",
                                       "p", "p.adj", "p.adj.signif")])
  print(wtest_out)
  if (!is.null(out_path)) fwrite(wtest_out, out_path, sep = "\t")
  ggplot(data, aes(x = group, y = .data[[y_var]], fill = group)) +
    geom_violin(linewidth = 0.2, alpha = 0.6, width = 0.8, colour = "black") +
    geom_boxplot(linewidth = 0.2, width = 0.12, outliers = FALSE,
                 colour = "black", aes(fill = group), alpha = 0.8) +
    stat_pvalue_manual(wtest, label = "p.adj.signif", tip.length = 0.01,
                       size = 3.2, colour = "black", family = "Helvetica") +
    scale_fill_manual(values = group_cols) +
    labs(title = title_str, y = y_lab, x = NULL) +
    base_theme + theme(legend.position = "none") +
    coord_cartesian(clip = "off")
}

