# ── 2.4 Additional BPs: count, consensus match, distance from top-1 ──────────

# 7-mer sequences keyed by exon (A = pos 6 of YNYURAY, 7-mer = intron_pos-5 : intron_pos+1)
nt_seqs <- psi_df %>%
  filter(grepl('wt', variant_id)) %>%
  select(exon_id, nt_seq) %>%
  distinct() %>%
  inner_join(bp_7mers, by = 'exon_id')

# Sequence-based scan for additional BP motifs
# YNYURAY: Y(C/T) N(any) Y(C/T) U(T) R(A/G) A(A) Y(C/T)
# Filter: pos4=T and pos6=A required; max 2 mismatches among variable positions 1,3,5,7

# Total 7-position consensus score (max 7; pos 2=N always = 1)
score_7mer <- function(s) {
  if (is.na(s) || nchar(s) < 7) return(NA_integer_)
  n <- toupper(strsplit(s, "")[[1]])
  as.integer(sum(c(n[1] %in% c("C","T"), TRUE,
                   n[3] %in% c("C","T"), n[4] == "T",
                   n[5] %in% c("A","G"), n[6] == "A",
                   n[7] %in% c("C","T"))))
}

# Invariant positions must match exactly: pos4=T, pos6=A
has_invariants <- function(s) {
  if (is.na(s) || nchar(s) < 7) return(FALSE)
  n <- toupper(strsplit(s, "")[[1]])
  n[4] == "T" & n[6] == "A"
}

# Matches among the 4 variable positions: 1(Y), 3(Y), 5(R), 7(Y) — max 4
variable_score <- function(s) {
  if (is.na(s) || nchar(s) < 7) return(NA_integer_)
  n <- toupper(strsplit(s, "")[[1]])
  as.integer(n[1] %in% c("C","T") + n[3] %in% c("C","T") +
             n[5] %in% c("A","G") + n[7] %in% c("C","T"))
}

top1_coord <- nt_seqs %>%
  filter(order == 1L) %>%
  mutate(nt_seq = substr(nt_seq, 1, 66)) %>%
  select(exon_id, nt_seq, top1_start = bp_start)

add_bp <- top1_coord %>%
  inner_join(groups, by = "exon_id") %>%
  mutate(
    candidates = map2(nt_seq, top1_start, function(seq, top1) {
      starts <- seq_len(nchar(seq) - 6L)
      starts <- starts[is.na(top1) | starts != top1]
      data.frame(kmer_start = starts,
                 kmer = vapply(starts, function(s) substr(seq, s, s + 6L), character(1)))
    })
  ) %>%
  select(-nt_seq) %>%
  unnest(candidates) %>%
  mutate(
    n_consensus  = vapply(kmer, score_7mer,    integer(1)),
    n_variable   = vapply(kmer, variable_score, integer(1)),
    dist_to_top1 = abs(kmer_start - top1_start)
  ) %>%
  filter(vapply(kmer, has_invariants, logical(1)),  # pos4=T and pos6=A required
         n_variable >= 2)                            # max 2 mismatches among pos 1,3,5,7


# ── Summary table: 1 row per exon ─────────────────────────────────────────────

# Top-1 BP info (seq and start) from bp_7mers
top1_info <- bp_7mers %>%
  filter(order == 1L) %>%
  select(exon_id, start_top1 = bp_start, top1_bp_seq = bp_seq)

# Nearest additional BP per exon (closest to top-1 by position)
nearest_add <- add_bp %>%
  group_by(exon_id) %>%
  slice_min(dist_to_top1, n = 1, with_ties = FALSE) %>%
  ungroup() %>%
  select(exon_id,
         nearest_2nd_bp_start = kmer_start,
         nearest_2nd_bp_seq   = kmer,
         distance              = dist_to_top1)

# Count of additional BPs per exon
n_add_tbl <- add_bp %>%
  group_by(exon_id) %>%
  summarise(n_additional_bp = n(), .groups = "drop")

# One row per exon; exons with 0 additional BPs get n_additional_bp=0 and NA for nearest
add_bp_summary <- groups %>%
  left_join(top1_info,   by = "exon_id") %>%
  left_join(n_add_tbl,   by = "exon_id") %>%
  left_join(nearest_add, by = "exon_id") %>%
  select(exon_id, group, top1_bp_seq, start_top1,
         n_additional_bp, nearest_2nd_bp_start, nearest_2nd_bp_seq, distance) %>%
  mutate(n_additional_bp = replace_na(n_additional_bp, 0L),
         distance = replace_na(distance, 0L))

add_bp_stats_by_group <- add_bp_summary %>%
  group_by(group) %>%
  summarise(n = n(),
            median_n_add = median(n_additional_bp),
            pct_with_add = round(100 * mean(n_additional_bp > 0), 1),
            median_nt_nearest = median(distance),
            .groups = "drop")
cat("\n=== Additional BP summary (pos4=T, pos6=A, ≥2 variable matches) ===\n")
print(add_bp_stats_by_group)
fwrite(add_bp_stats_by_group, file.path(results_dir, "add_bp_stats_by_group.tsv"), sep = "\t")

fwrite(add_bp_summary, file.path(results_dir, "additional_bp_summary.tsv"), sep = "\t")

# -- Plot 1: number of additional BPs per exon (0 included) --
p_nadd <- plot_group_violin(add_bp_summary, "n_additional_bp",
                            "Number of additional BPs",
                            "Additional BPs",
                            step_increase = 0.1,
                            out_path = file.path(results_dir, "wtest_n_additional_bp.tsv"))

ggsave(file.path(plot_dir, "violin_n_additional_bp_by_group.png"), p_nadd, height = 5, width = 6)

# -- Plot 2: nearest distance from top-1 to nearest additional BP --
# exons with n_additional_bp == 0 are excluded (distance = NA)
p_nearest <- plot_group_violin(
  add_bp_summary %>% filter(!is.na(distance)),
