# ── 2.5 Reference dataset vs predicted: match rates ───────────────────────────

TOLERANCES <- 0:4

# Add cluster label to bp_7mers for use as 'pred'
pred <- bp_7mers %>%
  left_join(groups %>%
              mutate(cluster_label = case_when(
                group == "Yes\nManual"    ~ "Manual",
                group == "Yes\nPredicted" ~ "Predicted Cluster 1",
                group == "No\nPredicted"  ~ "Predicted Cluster 2"
              )) %>%
              select(exon_id, cluster_label),
            by = "exon_id") %>%
  mutate(label_group = case_when(
    label == "manual"                         ~ "Yes\nManual",
    cluster_label == "Predicted Cluster 1"    ~ "Yes\nPredicted",
    cluster_label == "Predicted Cluster 2"    ~ "No\nPredicted",
    TRUE                                      ~ "Predicted (top-1)"
  )) %>%
  filter(label_group != "Predicted (top-1)")

build_merged <- function(ref) {
  inner_join(ref, pred, by = "exon_id", suffix = c("_ref", "_pred"),
             relationship = "many-to-many") %>%
    mutate(pred_bp_pos = bp_end_pred - 1L,
           dist        = abs(intron_up_coord - pred_bp_pos)) %>%
    {
      out <- .
      for (tol in TOLERANCES)
        out[[paste0("match_tol", tol)]] <- out$dist <= tol
      out
    }
}

merged_mercer     <- build_merged(mercer)
merged_taggart    <- build_merged(taggart)
merged_labranchor <- build_merged(labranchor)

exon_match_rate <- function(data, lbl, max_order, tol_col) {
  data %>%
    filter(label == lbl, order <= max_order) %>%
    group_by(exon_id) %>%
    summarise(any_match = any(.data[[tol_col]]), .groups = "drop") %>%
    summarise(matched = sum(any_match), total = n(), rate = mean(any_match))
}

summary_table <- function(merged_data, dataset_name) {
  map_dfr(TOLERANCES, function(tol) {
    tol_col <- paste0("match_tol", tol)
    bind_rows(
      exon_match_rate(merged_data, "manual", 1L, tol_col) %>%
        mutate(label = "manual", top_n = 1L),
      map_dfr(1:3, function(k) {
        exon_match_rate(merged_data, "predicted", k, tol_col) %>%
          mutate(label = "predicted", top_n = k)
      })
    ) %>% mutate(tolerance = tol)
  }) %>%
    mutate(dataset = dataset_name) %>%
    select(dataset, label, top_n, tolerance, matched, total, rate)
}

cat("\n=== Exon-level match rate ===\n")
match_results <- bind_rows(
  summary_table(merged_mercer,     "Mercer"),
  summary_table(merged_taggart,    "Taggart"),
  summary_table(merged_labranchor, "LaBranchoR")
)
print(match_results, n = Inf)
fwrite(match_results, file.path(results_dir, "match_results.tsv"), sep = "\t")

