# ── 2.7 Cross-comparisons between reference datasets ─────────────────────────

cross_compare <- function(ref_a, name_a, ref_b, name_b) {
  shared_ids <- intersect(ref_a$exon_id, ref_b$exon_id)
  col_a <- paste0("coord_", tolower(name_a))
  col_b <- paste0("coord_", tolower(name_b))

  cat(sprintf("\n=== %s vs %s | shared exons: %d ===\n", name_a, name_b, length(shared_ids)))

  closest <- ref_a %>%
    filter(exon_id %in% shared_ids) %>%
    select(exon_id, !!col_a := intron_up_coord) %>%
    inner_join(
      ref_b %>% filter(exon_id %in% shared_ids) %>%
        select(exon_id, !!col_b := intron_up_coord),
      by = "exon_id", relationship = "many-to-many"
    ) %>%
    mutate(dist = abs(.data[[col_a]] - .data[[col_b]])) %>%
    group_by(exon_id, .data[[col_a]]) %>%
    slice_min(dist, n = 1, with_ties = FALSE) %>%
    ungroup()

  for (tol in TOLERANCES)
    cat(sprintf("  ±%d nt: %d / %d (%.1f%%)\n",
                tol, sum(closest$dist <= tol), nrow(closest),
                100 * mean(closest$dist <= tol)))

  out <- sprintf("%s_vs_%s_bp_comparison.tsv", tolower(name_a), tolower(name_b))
  fwrite(closest, file.path(results_dir, out), sep = "\t")
  cat("Saved:", out, "\n")
}

cross_compare(mercer,  "Mercer",  taggart,    "Taggart")
cross_compare(mercer,  "Mercer",  labranchor, "LaBranchoR")
cross_compare(taggart, "Taggart", labranchor, "LaBranchoR")

