# Top-1 BP per exon. For LaBranchoR predicted BPs, bp_end and intron_up_coord
# are equivalent (bp_end - 1 = intron_up_coord = canonical A position).
top1 <- bp_7mers %>%
  filter(order == 1L) %>%
  mutate(intron_up_coord_bp = bp_end - 1L)

exon_coord_tbl <- fread(
  here("libraries_design", "02_mutagenesis_libraries", "output", "genomic_coord_mut.tsv"),
  sep = '\t'
)
exon_coord_tbl <- exon_coord_tbl %>%
  filter(!grepl('del', identifier), start <= 70) %>%
  select(exon, start, CHROM, POS) %>%
  rename(chrom = CHROM, hg38_bpA_pos = POS) %>%
  distinct()

# Genomic coordinates of the canonical A
top1_coords <- top1 %>%
  inner_join(
    exon_coord_tbl,
    by = c("exon_id" = "exon", "intron_up_coord_bp" = "start")
  )

# LaBranchoR top-1 match (exact position)
lab_top1 <- labranchor %>%
  group_by(exon_id) %>%
  slice_max(prob, n = 1, with_ties = FALSE) %>%
  ungroup() %>%
  select(exon_id, lab_intron_up_coord = intron_up_coord, lab_prob = prob)

# Nearest Mercer BP per exon and distance
mercer_nearest <- top1 %>%
  select(exon_id, intron_up_coord_bp) %>%
  inner_join(mercer %>% select(exon_id, mercer_coord = intron_up_coord),
             by = "exon_id", relationship = "many-to-many") %>%
  mutate(dist = abs(intron_up_coord_bp - mercer_coord)) %>%
  group_by(exon_id) %>%
  slice_min(dist, n = 1, with_ties = FALSE) %>%
  ungroup() %>%
  select(exon_id, dist_mercer = dist)

# Nearest Taggart BP per exon and distance
taggart_nearest <- top1 %>%
  select(exon_id, intron_up_coord_bp) %>%
  inner_join(taggart %>% select(exon_id, taggart_coord = intron_up_coord),
             by = "exon_id", relationship = "many-to-many") %>%
  mutate(dist = abs(intron_up_coord_bp - taggart_coord)) %>%
  group_by(exon_id) %>%
  slice_min(dist, n = 1, with_ties = FALSE) %>%
  ungroup() %>%
  select(exon_id, dist_taggart = dist)

# WT PSI
wt_psi_tbl <- psi_df %>%
  filter(grepl("wt", variant_id)) %>%
  distinct(exon_id, wt_psi)

supp_table <- top1_coords %>%
  left_join(lab_top1,        by = "exon_id") %>%
  left_join(mercer_nearest,  by = "exon_id") %>%
  left_join(taggart_nearest, by = "exon_id") %>%
  left_join(wt_psi_tbl,      by = "exon_id") %>%
  left_join(groups %>% select(exon_id, bp_group = group), by = "exon_id") %>%
  mutate(
    match_labranchor  = !is.na(lab_intron_up_coord) &
      intron_up_coord_bp == lab_intron_up_coord,
    match_mercer_4nt  = !is.na(dist_mercer)  & dist_mercer  <= 4L,
    match_taggart_4nt = !is.na(dist_taggart) & dist_taggart <= 4L
  ) %>%
  select(
    exon_id, label, bp_group, wt_psi,
    chrom, hg38_bpA_pos,
    bp_start, bp_end, intron_up_coord_bp, bp_seq,
    lab_intron_up_coord, lab_prob, match_labranchor,
    dist_mercer,  match_mercer_4nt,
    dist_taggart, match_taggart_4nt
  ) %>%
  arrange(label, exon_id)

fwrite(supp_table, file.path(results_dir, "supplementary_table_top_BP.tsv"), sep = "\t")
